// Keyword Validator v3 — Expert-weighted scoring
const content = $input.first().json.content || $input.first().json.text || '';
const input = $('Webhook1').first().json.body;

const primary = (input.primary_keywords || '').trim();
function parseKeywords(raw) {
  if (!raw || typeof raw !== 'string') return [];
  return raw.split(',').map(k => k.trim()).filter(k => k.length > 0);
}
function escapeRegex(str) {
  return str.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

if (!primary) {
  return [{ json: { score: 0, passed: false, issues: ['No primary keyword provided'] } }];
}

const allSecondary = [...parseKeywords(input.secondary_keywords), ...parseKeywords(input.semantic_theme)]
  .filter((v, i, a) => a.indexOf(v) === i);

const lower = content.toLowerCase();
const primaryLower = primary.toLowerCase();
const plainText = content.replace(/<[^>]*>/g, '').replace(/[#*_]/g, '');
const words = plainText.split(/\s+/);

let score = 0;
const issues = [];

// 1. H1 contains primary keyword (20 pts — highest SEO value per Backlinko/Google)
const h1Match = content.match(/<h1[^>]*>(.*?)<\/h1>/i) || content.match(/^#\s+(.+)$/m);
const h1Text = h1Match ? h1Match[1].toLowerCase() : '';
if (!h1Match) {
  issues.push('MISSING H1 TAG');
} else if (h1Text.includes(primaryLower)) {
  score += 20;
} else {
  issues.push('Primary keyword NOT in H1. Found: "' + (h1Match[1] || '').substring(0, 60) + '"');
}

// 2. Primary in first 100 words (15 pts — Backlinko: "still makes a difference")
const first100 = words.slice(0, 100).join(' ').toLowerCase();
if (first100.includes(primaryLower)) {
  score += 15;
} else {
  issues.push('Primary keyword NOT in first 100 words');
}

// 3. Primary (or close variation) in at least one H2 (15 pts)
const h2Matches = content.match(/<h2[^>]*>(.*?)<\/h2>/gi) || content.match(/^##\s+(.+)$/gm) || [];
const h2Texts = h2Matches.map(h => h.replace(/<[^>]*>/g, '').replace(/^##\s+/, '').toLowerCase());
const primaryWords = primaryLower.split(/\s+/);
const minMatchWords = Math.ceil(primaryWords.length * 0.6);
const primaryInH2 = h2Texts.some(h => {
  if (h.includes(primaryLower)) return true;
  const matchedWords = primaryWords.filter(w => h.includes(w));
  return matchedWords.length >= minMatchWords;
});
if (primaryInH2) {
  score += 15;
} else {
  issues.push('Primary keyword (or variation) NOT in any H2');
}

// 4. Primary in conclusion (10 pts)
const paragraphs = plainText.split(/\n\n+/).filter(p => p.trim().length > 30);
const lastPara = paragraphs.length > 0 ? paragraphs[paragraphs.length - 1].toLowerCase() : '';
if (lastPara.includes(primaryLower)) {
  score += 10;
} else {
  issues.push('Primary keyword NOT in conclusion');
}

// 5. Keyword frequency check (10 pts — Backlinko: ~8 per 3200 words)
const primaryRegex = new RegExp(escapeRegex(primaryLower), 'gi');
const primaryCount = (lower.match(primaryRegex) || []).length;
const wordCount = words.length;
const expectedFreq = Math.max(3, Math.round((wordCount / 3200) * 8));
if (primaryCount >= expectedFreq - 1 && primaryCount <= expectedFreq * 2) {
  score += 10;
} else if (primaryCount >= 2) {
  score += 5;
  issues.push('Keyword frequency: ' + primaryCount + 'x (target: ~' + expectedFreq + 'x)');
} else {
  issues.push('Keyword used only ' + primaryCount + 'x (target: ~' + expectedFreq + 'x)');
}

// 6. All secondary/semantic keywords present (25 pts)
const secondaryResults = allSecondary.map(kw => ({
  keyword: kw,
  found: lower.includes(kw.toLowerCase())
}));
const secondaryFound = secondaryResults.filter(s => s.found).length;
const secondaryTotal = allSecondary.length || 1;
score += Math.round((secondaryFound / secondaryTotal) * 25);
const missing = secondaryResults.filter(s => !s.found).map(s => s.keyword);
if (missing.length > 0) {
  issues.push('MISSING secondary/semantic: ' + missing.join(' | '));
}

// 7. H2 keyword distribution (5 pts bonus — Surfer SEO best practice)
const keywordsInH2 = allSecondary.filter(kw =>
  h2Texts.some(h => h.includes(kw.toLowerCase()))
);
if (keywordsInH2.length >= 1) {
  score += 5;
}

// 8. Keyword bolding penalty (informational)
const boldedKeyword = content.match(new RegExp('\\*\\*[^*]*' + escapeRegex(primaryLower) + '[^*]*\\*\\*', 'i'));
if (boldedKeyword) {
  issues.push('WARNING: Primary keyword is bolded in body text');
}

const finalScore = Math.min(100, score);
const passed = finalScore >= 60 && h1Text.includes(primaryLower) && first100.includes(primaryLower);

return [{ json: {
  score: finalScore,
  passed,
  issues,
  checks: {
    primaryInH1: h1Text.includes(primaryLower),
    primaryInFirst100: first100.includes(primaryLower),
    primaryInH2: primaryInH2,
    primaryInConclusion: lastPara.includes(primaryLower),
    frequency: primaryCount + 'x (target: ~' + expectedFreq + 'x)',
    secondaryCoverage: secondaryFound + '/' + allSecondary.length,
    missingKeywords: missing,
    secondaryInH2s: keywordsInH2
  }
}}];

